import React, { useRef, useEffect } from 'react';

export default function WavyBackground({
  waveWidth = 2,
  speed = "slow",
  backgroundFill = "#080710"
}) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');

    let animationFrameId;
    let nt = 0; // noise/time counter

    const resizeCanvas = () => {
      canvas.width = canvas.parentElement.clientWidth;
      canvas.height = canvas.parentElement.clientHeight;
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    const colors = ["#38bdf8", "#818cf8", "#c084fc", "#e879f9", "#22d3ee"];
    const speedMultiplier = speed === "fast" ? 0.02 : 0.005;

    const render = () => {
      // Clear canvas with base background fill
      ctx.fillStyle = backgroundFill;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      nt += speedMultiplier;

      // Draw 5 separate waves
      for (let i = 0; i < 5; i++) {
        ctx.beginPath();
        ctx.lineWidth = waveWidth;
        ctx.strokeStyle = colors[i];

        // Draw sine wave path across x-axis
        for (let x = 0; x < canvas.width; x += 10) {
          // Compute Y offset using sine wave equations
          const y =
            canvas.height / 2 +
            Math.sin(x * 0.002 + nt + i * 2) * 50 * Math.sin(nt * 0.5 + i) +
            Math.sin(x * 0.005 + nt * 2) * 15;

          if (x === 0) {
            ctx.moveTo(x, y);
          } else {
            ctx.lineTo(x, y);
          }
        }
        ctx.stroke();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', resizeCanvas);
    };
  }, [waveWidth, speed, backgroundFill]);

  return (
    <div className="relative w-full h-full min-h-screen overflow-hidden">
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full block" />
    </div>
  );
}
